import{_ as a,o,c as t,a2 as i}from"./chunks/framework.IwO0Hdn_.js";const g=JSON.parse('{"title":"[UI / PRESENTATION] F-04.6 — Visualización del Hilo en Vista Detalle del Archivado","description":"","frontmatter":{},"headers":[],"relativePath":"backlog/F-04.6_visualizacion_hilo_detalle.md","filePath":"backlog/F-04.6_visualizacion_hilo_detalle.md","lastUpdated":null}'),n={name:"backlog/F-04.6_visualizacion_hilo_detalle.md"};function r(d,e,l,s,c,u){return o(),t("div",null,[...e[0]||(e[0]=[i('<h1 id="ui-presentation-f-04-6-—-visualizacion-del-hilo-en-vista-detalle-del-archivado" tabindex="-1">[UI / PRESENTATION] F-04.6 — Visualización del Hilo en Vista Detalle del Archivado <a class="header-anchor" href="#ui-presentation-f-04-6-—-visualizacion-del-hilo-en-vista-detalle-del-archivado" aria-label="Permalink to &quot;[UI / PRESENTATION] F-04.6 — Visualización del Hilo en Vista Detalle del Archivado&quot;">​</a></h1><p><strong>Épica:</strong> EPIC-04 — Histórico de Logs Archivados</p><h2 id="🏷️-categoria" tabindex="-1">🏷️ Categoría <a class="header-anchor" href="#🏷️-categoria" aria-label="Permalink to &quot;🏷️ Categoría&quot;">​</a></h2><p><strong>Categoría:</strong> <code>UI / Presentation</code><strong>Impacta en:</strong> Equipo Frontend (Livewire/Blade)</p><h2 id="📦-dependencias" tabindex="-1">📦 Dependencias <a class="header-anchor" href="#📦-dependencias" aria-label="Permalink to &quot;📦 Dependencias&quot;">​</a></h2><blockquote><p>Backlogs que deben estar <strong>completados</strong> antes de implementar esta feature.</p></blockquote><table tabindex="0"><thead><tr><th>Backlog</th><th>Motivo</th></tr></thead><tbody><tr><td><a href="./F-04.4_hilo_comentarios.html">F-04.4</a></td><td>Comentarios persistidos en DB y lógica de autoría implementada</td></tr><tr><td><a href="./F-04.5_rich_text_historico.html">F-04.5</a></td><td>Renderizado de HTML sanitizado en comentarios de seguimiento implementado</td></tr></tbody></table><p><strong>Prioridad:</strong> <code>Must</code></p><hr><p><strong>Descripción:</strong> Como administrador del sistema Quiero que la vista detalle de un log archivado muestre el hilo completo de comentarios Para tener toda la historia de la incidencia en un único lugar sin necesidad de navegar</p><p><strong>Criterios de Aceptación (Checklist):</strong></p><ul><li>[ ] <strong>Escenario 1 (Happy Path):</strong> Dado que abro el detalle de un log archivado con 3 comentarios, cuando se carga la vista, entonces veo los metadatos del log original arriba y el hilo de comentarios abajo, en orden cronológico.</li><li>[ ] <strong>Escenario 2 (Renderizado rich text):</strong> Dado que un comentario contiene texto formateado e imágenes, cuando se renderiza en la vista detalle, entonces el HTML sanitizado se muestra correctamente (negrita, imágenes, listas).</li><li>[ ] <strong>Escenario 3 (Añadir desde detalle):</strong> Dado que estoy en la vista detalle, cuando pulso &quot;Añadir comentario&quot;, entonces el editor TipTap aparece al final del hilo sin abandonar la vista detalle.</li><li>[ ] <strong>Escenario 4 (Seguridad renderizado):</strong> Dado que el HTML de un comentario está almacenado, cuando se renderiza en la vista Blade, entonces se usa <code>{!! $comment-&gt;content !!}</code> solo sobre contenido previamente sanitizado en backend con HTMLPurifier (nunca sobre input crudo del usuario).</li><li>[ ] <strong>Requisito Técnico:</strong> La vista <code>GET /historico/{id}</code> carga el modelo <code>ArchivedLog</code> con la relación <code>comments</code> mediante Eloquent eager loading (<code>with(&#39;comments.user&#39;)</code>). Limitar a máximo 100 comentarios por carga inicial; paginar si supera ese umbral.</li></ul>',12)])])}const h=a(n,[["render",r]]);export{g as __pageData,h as default};
